#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e3;
int n,w[MAXN][MAXN],maxx;
signed main(void)
{
	cin>>n;
	FOR(i,1,5e2)
	{
		FOR(j,1,5e2)
		{
			if(i==j)w[i][j]=0;
			else w[i][j]=inf;
		}
	}
	FOR(i,1,n)
	{
		int s,x,y;
		char x1,y1;
		cin>>x1>>y1>>s;
		x=x1,y=y1;
		w[x][y]=w[y][x]=min(s,w[y][x]);
	}
	FOR(k,1,5e2)
	{
		FOR(i,1,5e2)
		{
			FOR(j,1,5e2)
			{
				if(w[i][k]!=inf&&w[k][j]!=inf)
				{
					w[i][j]=min(w[i][j],w[i][k]+w[k][j]);
				}
			}
		}
	}
	char tape;
	int res=inf;
	FOR(i,'A','Y')
	{
		if(w[i][90]<res)
		{
			res=w[i][90];
			tape=char(i);
		}
	}
	cout<<tape<<' '<<res;
	return false;
}
